mapper.select:
SELECT TPWP.ID, TPWP.PLAN_TYPE, TPWP.TRUST_ID, TDS.SCN, TPWP.HATCH, TPWP.MASS_NAMES_TARGET, TPWP.MASS_NAMES_SOURCE, TPWP.EQUIPMENT_NAMES_FRONT, TPWP.EQUIPMENT_NAMES_BACK, TPWP.EQUIPMENT_NAMES_ASSIST, TPWP.EQUIPMENT_NAMES_RESHIPMENT, TPWP.COMPANY_NAME, TPWP.EXAMINE_BY, TPWP.WORK_DATE, TPWP.CLASS_CODE, TPWP.CLASS_NAME, TDSI.LOAD_UNLOAD, CASE WHEN TPWP.SHIPVOYAGE_ID IS NOT NULL THEN TO_CHAR (TDS.SHIP_NAME) || '_' || TO_CHAR (TDSI.VOYAGE) END shipvoyageLabel, TPWP.PLAN_NO, TPWP.PROCESS_CODE, TPWP.PROCESS_NAME, TPWP.DEPT_NAME, TPWP.QUANTITY_PLAN, TPWP.TON_PLAN, TPWP.START_TIME_PLAN, TPWP.END_TIME_PLAN, TPWP.START_WORK_TIME, TPWP.END_WORK_TIME, TPWP.REMARK, TPWP.STATUS, MC.NM STATUS_LABEL, TPWP.BERTH_NAME, TPWP.FRONT_TALLY_BY_NAME, TPWP.BACK_TALLY_BY_NAME, TPWP.DISPATCH_BY_NAME, TPWP.EQUIPMENT_NAMES_FRONT, TPWP.EQUIPMENT_NAMES_BACK, TPWP.EQUIPMENT_NAMES_ASSIST, TPWP.EQUIPMENT_NAMES_RESHIPMENT, T8.CARGO_OWNER_NAME, T8.CARGO_OWNER_ID, T8.CARGO_AGENT_NAME, T8.CARGO_NAME, T8.CARGO_CODE, T8.CARGO_INFO_NO, T5.TRUST_NO, T2.NUM AS LABOR_NUM, CASE WHEN LISTAGG ( TO_CHAR( TPWT. TICKET_TYPE ), ',' ) WITHIN GROUP ( ORDER BY TPWT. TICKET_TYPE ) like '%1%' THEN '已签票' ELSE '待签票' END IS_SIGNED,
CASE WHEN LISTAGG ( TO_CHAR( TPWT. TICKET_TYPE ), ',' ) WITHIN GROUP ( ORDER BY TPWT. TICKET_TYPE ) like '%2%' THEN '已签票' ELSE '待签票' END IS_SIGNED_KC FROM T_PRD_WORK_PLAN TPWP LEFT JOIN T_DIS_SHIPVOYAGE TDS ON TPWP.SHIPVOYAGE_ID = TDS. ID LEFT JOIN M_SHIP MS ON TDS.SHIP_ID = MS. ID LEFT JOIN T_DIS_SHIPVOYAGE_ITEM TDSI ON TPWP.SHIPVOYAGE_ITEM_ID = TDSI. ID JOIN M_CONSTANTS MC ON TPWP.STATUS = MC.CD AND MC.TYPE_CD = 'WORK_PLAN_STATUS' LEFT JOIN T_PRD_WORK_TICKET TPWT ON TPWP. ID = TPWT.WORK_PLAN_ID LEFT JOIN T_BUS_TRUST T5 ON TPWP.TRUST_ID = T5. ID LEFT JOIN ( SELECT A .TRUST_ID, regexp_replace( LISTAGG (TO_CHAR(T6.CARGO_INFO_NO), ',') WITHIN GROUP (ORDER BY T6.CARGO_INFO_NO) , '([^,]+)(,\1)*(,|$)', '\1\3' ) CARGO_INFO_NO, regexp_replace( LISTAGG (TO_CHAR(T6.CARGO_NAME), ',') WITHIN GROUP (ORDER BY T6.CARGO_NAME) , '([^,]+)(,\1)*(,|$)', '\1\3' ) CARGO_NAME, regexp_replace( LISTAGG (TO_CHAR(T6.CARGO_CODE), ',') WITHIN GROUP (ORDER BY T6.CARGO_CODE) , '([^,]+)(,\1)*(,|$)', '\1\3' ) CARGO_CODE, regexp_replace( LISTAGG (TO_CHAR(T6.CARGO_OWNER_NAME), ',') WITHIN GROUP (ORDER BY T6.CARGO_OWNER_NAME) , '([^,]+)(,\1)*(,|$)', '\1\3' ) CARGO_OWNER_NAME, regexp_replace( LISTAGG (TO_CHAR(T6.CARGO_OWNER_ID), ',') WITHIN GROUP (ORDER BY T6.CARGO_OWNER_ID) , '([^,]+)(,\1)*(,|$)', '\1\3' ) CARGO_OWNER_ID, regexp_replace( LISTAGG (TO_CHAR(T6.CARGO_AGENT_NAME), ',') WITHIN GROUP (ORDER BY T6.CARGO_AGENT_NAME) , '([^,]+)(,\1)*(,|$)', '\1\3' ) CARGO_AGENT_NAME, regexp_replace( LISTAGG (TO_CHAR(T6.PACKING_CODE), ',') WITHIN GROUP (ORDER BY T6.PACKING_CODE) , '([^,]+)(,\1)*(,|$)', '\1\3' ) PACKING_CODE FROM T_BUS_CARGO_INFO T6, T_BUS_TRUST_CARGO A, T_BUS_TRUST T5 WHERE A .CARGO_INFO_ID = T6. ID AND T5. ID = A .TRUST_ID GROUP BY A .TRUST_ID ) T8 ON T8.TRUST_ID = TPWP.TRUST_ID LEFT JOIN T_PRD_DISPATCH T2 ON TPWP. ID = T2.WORK_PLAN_ID AND T2.DISPATCH_TYPE = '2' WHERE TPWP.STATUS != 10
and (TPWP.FRONT_TALLY_BY like #{loginIdLike} OR TPWP.BACK_TALLY_BY like #{loginIdLike} OR TPWP.DISPATCH_BY like #{loginIdLike})
AND TPWP.WORK_DATE = #{workDate}
AND TPWP.CLASS_CODE = #{classCode}
AND T5.TRUST_NO = #{trustNo}
AND TPWP.PLAN_TYPE = #{planType}
AND TPWP.SHIPVOYAGE_ITEM_ID = #{shipvoyageItemId}
AND T8.CARGO_OWNER_ID like #{cargoOwnerIdLike}
AND T8.CARGO_CODE like #{cargoCodeLike}
AND T5.PORT_CODE = #{portCode}
AND T8.PACKING_CODE like #{packageCodeLike}
GROUP BY TPWP.ID, TPWP.PLAN_TYPE, TPWP.TRUST_ID, TDS.SCN, TPWP.HATCH, TPWP.MASS_NAMES_TARGET, TPWP.MASS_NAMES_SOURCE, TPWP.EQUIPMENT_NAMES_FRONT, TPWP.EQUIPMENT_NAMES_BACK, TPWP.EQUIPMENT_NAMES_ASSIST, TPWP.EQUIPMENT_NAMES_RESHIPMENT, TPWP.COMPANY_NAME, TPWP.EXAMINE_BY, TPWP.WORK_DATE, TPWP.CLASS_CODE, TPWP.CLASS_NAME, TDSI.LOAD_UNLOAD, CASE WHEN TPWP.SHIPVOYAGE_ID IS NOT NULL THEN TO_CHAR (TDS.SHIP_NAME) || '_' || TO_CHAR (TDSI.VOYAGE) END, TPWP.PLAN_NO, TPWP.PROCESS_CODE, TPWP.PROCESS_NAME, TPWP.DEPT_NAME, TPWP.QUANTITY_PLAN, TPWP.TON_PLAN, TPWP.START_TIME_PLAN, TPWP.END_TIME_PLAN, TPWP.START_WORK_TIME, TPWP.END_WORK_TIME, TPWP.REMARK, TPWP.STATUS, MC.NM, TPWP.BERTH_NAME, TPWP.FRONT_TALLY_BY_NAME, TPWP.BACK_TALLY_BY_NAME, TPWP.DISPATCH_BY_NAME, TPWP.EQUIPMENT_NAMES_FRONT, TPWP.EQUIPMENT_NAMES_BACK, TPWP.EQUIPMENT_NAMES_ASSIST, TPWP.EQUIPMENT_NAMES_RESHIPMENT, T8.CARGO_OWNER_NAME, T8.CARGO_OWNER_ID, T8.CARGO_AGENT_NAME, T8.CARGO_NAME, T8.CARGO_CODE, T8.CARGO_INFO_NO, T5.TRUST_NO, T2.NUM ORDER By T5.TRUST_NO

SELECT TPWP.ID, TPWP.PLAN_TYPE, TPWP.TRUST_ID, TPWP.HATCH, TPWP.MASS_NAMES_TARGET, TPWP.MASS_NAMES_SOURCE, TPWP.EQUIPMENT_NAMES_FRONT, TPWP.EQUIPMENT_NAMES_BACK, TPWP.EQUIPMENT_NAMES_ASSIST, TPWP.EQUIPMENT_NAMES_RESHIPMENT, TPWP.COMPANY_NAME, TPWP.EXAMINE_BY, TPWP.WORK_DATE, TPWP.CLASS_CODE, TPWP.CLASS_NAME, TDSI.LOAD_UNLOAD, CASE WHEN TPWP.SHIPVOYAGE_ID IS NOT NULL THEN TO_CHAR (TDS.SHIP_NAME) || '_' || TO_CHAR (TDSI.VOYAGE) END shipvoyageLabel, TPWP.PLAN_NO, TPWP.PROCESS_CODE, TPWP.PROCESS_NAME, TPWP.DEPT_NAME, TPWP.QUANTITY_PLAN, TPWP.TON_PLAN, TPWP.START_TIME_PLAN, TPWP.END_TIME_PLAN, TPWP.START_WORK_TIME, TPWP.END_WORK_TIME, TPWP.REMARK, TPWP.STATUS, MC.NM STATUS_LABEL, TPWP.BERTH_NAME, TPWP.FRONT_TALLY_BY_NAME, TPWP.BACK_TALLY_BY_NAME, TPWP.DISPATCH_BY_NAME, TPWP.EQUIPMENT_NAMES_FRONT, TPWP.EQUIPMENT_NAMES_BACK, TPWP.EQUIPMENT_NAMES_ASSIST, TPWP.EQUIPMENT_NAMES_RESHIPMENT, T6.CARGO_OWNER_NAME, T6.CARGO_OWNER_ID, T7.CARGO_AGENT_NAME, T8.CARGO_NAME, T8.CARGO_CODE, T5.TRUST_NO, T5.TYPE, T2.NUM AS LABOR_NUM, CASE WHEN TPWT.ID IS NULL THEN '待审核' ELSE TO_CHAR( TPWT.WORK_TICKET_STATUS_NAME ) END WORK_TICKET_STATUS_NAME, CASE WHEN LISTAGG ( TO_CHAR( TPWT. TICKET_TYPE ), ',' ) WITHIN GROUP ( ORDER BY TPWT. TICKET_TYPE ) IS NULL THEN '待签票' WHEN LISTAGG ( TO_CHAR( TPWT. TICKET_TYPE ), ',' ) WITHIN GROUP ( ORDER BY TPWT. TICKET_TYPE ) = '1' THEN '调度已签票' WHEN LISTAGG ( TO_CHAR( TPWT. TICKET_TYPE ), ',' ) WITHIN GROUP ( ORDER BY TPWT. TICKET_TYPE ) = '2' THEN '库场已签票' ELSE '调度/库场已签票' END IS_SIGNED
FROM T_PRD_WORK_PLAN TPWP LEFT JOIN T_DIS_SHIPVOYAGE TDS ON TPWP.SHIPVOYAGE_ID = TDS. ID LEFT JOIN M_SHIP MS ON TDS.SHIP_ID = MS. ID LEFT JOIN T_DIS_SHIPVOYAGE_ITEM TDSI ON TPWP.SHIPVOYAGE_ITEM_ID = TDSI. ID JOIN M_CONSTANTS MC ON TPWP.STATUS = MC.CD AND MC.TYPE_CD = 'WORK_PLAN_STATUS' LEFT JOIN T_PRD_WORK_TICKET TPWT ON TPWP. ID = TPWT.WORK_PLAN_ID LEFT JOIN T_BUS_TRUST T5 ON TPWP.TRUST_ID = T5. ID LEFT JOIN ( SELECT REGEXP_REPLACE ( LISTAGG ( TO_CHAR (CARGO_OWNER_NAME), ',' ) WITHIN GROUP (ORDER BY CARGO_OWNER_NAME), '([^,]+)(,\1)+', '\1' ) CARGO_OWNER_NAME, TRUST_ID, REGEXP_REPLACE ( LISTAGG ( TO_CHAR (CARGO_OWNER_ID), ',' ) WITHIN GROUP (ORDER BY CARGO_OWNER_ID), '([^,]+)(,\1)+', '\1' ) CARGO_OWNER_ID FROM T_BUS_TRUST_CARGO GROUP BY TRUST_ID ) T6 ON T5. ID = T6.TRUST_ID LEFT JOIN ( SELECT REGEXP_REPLACE ( LISTAGG (TO_CHAR(CARGO_NAME), ',') WITHIN GROUP (ORDER BY CARGO_NAME), '([^,]+)(,\1)+', '\1' ) CARGO_NAME, REGEXP_REPLACE ( LISTAGG (TO_CHAR(CARGO_CODE), ',') WITHIN GROUP (ORDER BY CARGO_CODE), '([^,]+)(,\1)+', '\1' ) CARGO_CODE, TRUST_ID FROM T_BUS_TRUST_CARGO GROUP BY TRUST_ID ) T8 ON T5. ID = T8.TRUST_ID LEFT JOIN ( SELECT REGEXP_REPLACE ( LISTAGG ( TO_CHAR (CARGO_AGENT_NAME), ',' ) WITHIN GROUP (ORDER BY CARGO_AGENT_NAME), '([^,]+)(,\1)+', '\1' ) CARGO_AGENT_NAME, TRUST_ID FROM T_BUS_TRUST_CARGO GROUP BY TRUST_ID ) T7 ON T5. ID = T7.TRUST_ID LEFT JOIN T_PRD_DISPATCH T2 ON TPWP. ID = T2.WORK_PLAN_ID AND T2.DISPATCH_TYPE = '2' WHERE TPWP.STATUS != 10
AND TPWP.WORK_DATE = #{workDate}
AND TPWP.CLASS_CODE = #{classCode}
AND TPWP.PLAN_TYPE = #{planType}
AND T5.TRUST_NO = #{trustNo}
AND T5.PORT_CODE = #{portCode}
GROUP BY TPWP.ID, TPWP.PLAN_TYPE, TPWP.TRUST_ID, TPWP.HATCH, TPWP.MASS_NAMES_TARGET, TPWP.MASS_NAMES_SOURCE, TPWP.EQUIPMENT_NAMES_FRONT, TPWP.EQUIPMENT_NAMES_BACK, TPWP.EQUIPMENT_NAMES_ASSIST, TPWP.EQUIPMENT_NAMES_RESHIPMENT, TPWP.COMPANY_NAME, TPWP.EXAMINE_BY, TPWP.WORK_DATE, TPWP.CLASS_CODE, TPWP.CLASS_NAME, TDSI.LOAD_UNLOAD, CASE WHEN TPWP.SHIPVOYAGE_ID IS NOT NULL THEN TO_CHAR (TDS.SHIP_NAME) || '_' || TO_CHAR (TDSI.VOYAGE) END, TPWP.PLAN_NO, TPWP.PROCESS_CODE, TPWP.PROCESS_NAME, TPWP.DEPT_NAME, TPWP.QUANTITY_PLAN, TPWP.TON_PLAN, TPWP.START_TIME_PLAN, TPWP.END_TIME_PLAN, TPWP.START_WORK_TIME, TPWP.END_WORK_TIME, TPWP.REMARK, TPWP.STATUS, MC.NM, TPWP.BERTH_NAME, TPWP.FRONT_TALLY_BY_NAME, TPWP.BACK_TALLY_BY_NAME, TPWP.DISPATCH_BY_NAME, TPWP.EQUIPMENT_NAMES_FRONT, TPWP.EQUIPMENT_NAMES_BACK, TPWP.EQUIPMENT_NAMES_ASSIST, TPWP.EQUIPMENT_NAMES_RESHIPMENT, T6.CARGO_OWNER_NAME, T6.CARGO_OWNER_ID, T7.CARGO_AGENT_NAME, T8.CARGO_NAME, T8.CARGO_CODE, T5.TRUST_NO, T5.TYPE, T2.NUM, CASE WHEN TPWT.ID IS NULL THEN '待审核' ELSE TO_CHAR( TPWT.WORK_TICKET_STATUS_NAME ) END ORDER BY PLAN_NO

SELECT TBCI.ID,
TBCI.SCN, TBCI.SHIP_NAME, TBCI.CARGO_INFO_NO, TBCI.CARGO_OWNER_ID, TBCI.CARGO_OWNER_NAME, TBCI.CARGO_AGENT_ID, TBCI.CARGO_AGENT_NAME, TBCI.CARGO_CODE, TBCI.CARGO_NAME, TBCI.TRADE_TYPE, TBCI.PACKING_CODE, TBCI.PACKING_NAME, TBCI.COMPANY_ID, TBCI.COMPANY_NAME, TBCI.PARENT_ID, TBCI.ROOT_ID, TBCI.QUANTITY, TBCI.TON, TBCI.RIGHTS_QUANTITY, TBCI.SURPLUS_RIGHTS_QUANTITY, TBCI.IS_CLEAR, TBCI.CLEAR_BY, TBCI.CLEAR_BY_NAME, TBCI.CLEAR_DATE, TBCI.CREATE_BY, TBCI.CREATE_BY_NAME, TBCI.CREATE_TIME, TBCI.UPDATE_BY, TBCI.UPDATE_BY_NAME, TBCI.UPDATE_TIME, TBTC.TRUST_ID, TBTC.ID TRUST_CARGO_ID,
TBCI.CARGO_NAME || '/' || TBCI.CARGO_OWNER_NAME || '/' || TBCI.CARGO_INFO_NO CARGO_LABEL, TBT.PROCESS_CODE, TBT.PROCESS_NAME FROM T_PRD_WORK_PLAN TPWPT JOIN T_BUS_TRUST TBT ON TPWPT.TRUST_ID = TBT.ID JOIN T_BUS_TRUST_CARGO TBTC ON TBT.ID = TBTC.TRUST_ID JOIN T_BUS_CARGO_INFO TBCI ON TBTC.CARGO_INFO_ID = TBCI.ID WHERE TPWPT.id = #{workPlanId, jdbcType=BIGINT}

SELECT TBCI.ID, TPWPT.ID WORK_PLAN_ID, TBCI.SHIPVOYAGE_ID, TBCI.SHIPVOYAGE_ITEM_ID, TBCI.SCN, TBCI.SHIP_NAME, TBCI.CARGO_INFO_NO, TBCI.CARGO_OWNER_ID, TBCI.CARGO_OWNER_NAME, TBCI.CARGO_AGENT_ID, TBCI.CARGO_AGENT_NAME, TBCI.CARGO_CODE, TBCI.CARGO_NAME, TBCI.TRADE_TYPE, TBCI.PACKING_CODE, TBCI.PACKING_NAME, TBCI.COMPANY_ID, TBCI.COMPANY_NAME, TBCI.PARENT_ID, TBCI.ROOT_ID, TBCI.QUANTITY, TBCI.TON, TBCI.RIGHTS_QUANTITY, TBCI.SURPLUS_RIGHTS_QUANTITY, TBCI.IS_CLEAR, TBCI.CLEAR_BY, TBCI.CLEAR_BY_NAME, TBCI.CLEAR_DATE, TBCI.CREATE_BY, TBCI.CREATE_BY_NAME, TBCI.CREATE_TIME, TBCI.UPDATE_BY, TBCI.UPDATE_BY_NAME, TBCI.UPDATE_TIME, TBTC.TRUST_ID, TBTC.ID TRUST_CARGO_ID,
TBCI.CARGO_NAME || '/' || TBCI.CARGO_OWNER_NAME || '/' || TBCI.CARGO_INFO_NO CARGO_LABEL, TBT.PROCESS_CODE, TBT.PROCESS_NAME FROM T_PRD_WORK_PLAN TPWPT JOIN T_BUS_TRUST TBT ON TPWPT.TRUST_ID = TBT.ID JOIN T_BUS_TRUST_CARGO TBTC ON TBT.ID = TBTC.TRUST_ID JOIN T_BUS_CARGO_INFO TBCI ON TBTC.CARGO_INFO_ID = TBCI.ID WHERE TPWPT.id IN
#{item}

SELECT
ID,
COMPANY_ID,
COMPANY_NAME,
DEPT_ID,
DEPT_NAME,
PIECE_PROJECT_CODE,
PIECE_PROJECT_NAME,
IS_UPDATE_STORAGE,
CREATE_BY,
CREATE_BY_NAME,
CREATE_TIME,
UPDATE_BY,
UPDATE_BY_NAME,
UPDATE_TIME
FROM M_PIECE_WORK_TEAM


        ID = #{id, jdbcType=BIGINT}


        AND COMPANY_ID = #{companyId, jdbcType=BIGINT}


        AND COMPANY_NAME = #{companyName, jdbcType=VARCHAR}


        AND DEPT_ID = #{deptId, jdbcType=BIGINT}


        AND DEPT_NAME = #{deptName, jdbcType=VARCHAR}


        AND PIECE_PROJECT_CODE = #{pieceProjectCode, jdbcType=VARCHAR}


        AND PIECE_PROJECT_NAME = #{pieceProjectName, jdbcType=VARCHAR}


        AND IS_UPDATE_STORAGE = #{isUpdateStorage, jdbcType=VARCHAR}


        AND CREATE_BY = #{createBy, jdbcType=BIGINT}


        AND CREATE_BY_NAME = #{createByName, jdbcType=VARCHAR}


        AND CREATE_TIME = #{createTime, jdbcType=TIMESTAMP}


        AND UPDATE_BY = #{updateBy, jdbcType=BIGINT}


        AND UPDATE_BY_NAME = #{updateByName, jdbcType=VARCHAR}


        AND UPDATE_TIME = #{updateTime, jdbcType=TIMESTAMP}


ORDER BY
    DEPT_NAME

SELECT ID
FROM M_STORAGE_YARD
WHERE STORAGE_YARD_LEVEL = '3'
  AND PARENT_ID = #{parentId,jdbcType=BIGINT}
  AND STORAGE_YARD_NM = #{storageYardNm,jdbcType=VARCHAR}

mapper.delete:
DELETE
FROM T_PRD_WORK_TICKET_DETAIL
WHERE WORK_TICKET_ID = #{workTicketId, jdbcType=BIGINT}

DELETE
FROM T_PRD_WORK_TICKET_LABOR
WHERE WORK_TICKET_ID = #{workTicketId, jdbcType=BIGINT}

DELETE
FROM T_PRD_WORK_TICKET
WHERE WORK_PLAN_ID = #{workPlanId, jdbcType=BIGINT} AND TICKET_TYPE = #{type,jdbcType=VARCHAR}

mapper.select:
SELECT REGEXP_REPLACE ( LISTAGG ( TO_CHAR ( A2.SHIP_NAME || '_' || A1.VOYAGE ), ',' ) WITHIN GROUP (
ORDER BY A2.SHIP_NAME || '_' || A1.VOYAGE ), '([^,]+)(,\1)*(,|$)', '\1\3' ) FROM T_DIS_SHIPVOYAGE_ITEM A1 LEFT JOIN T_DIS_SHIPVOYAGE A2 ON A2.ID = A1.SHIPVOYAGE_ID WHERE A1.ID IN
#{id}

mapper.delete:
DELETE FROM T_PRD_SALARY
WHERE WORK_TICKET_DETAIL_ID IN

    #{workTicketDetailId}

mapper.select:
SELECT * from T_PRD_WORK_TICKET


        WORK_PLAN_ID = #{workPlanId}


        and TICKET_TYPE = #{ticketType}

SELECT
     SUM (A1.QUANTITY) "quantity",
     SUM (A1.TON) "ton"
 FROM
     T_YARD_TALLY_ITEM A1
 LEFT JOIN T_YARD_TALLY A2 ON A2. ID = A1.TALLY_ID
 WHERE
     A2.PLAN_ID =#{workPlanId,jdbcType=BIGINT}
 AND A1.CARGO_INFO_ID = #{cargoInfoId,jdbcType=BIGINT}
 AND A2.PROCESS_CODE = #{processDetailCode,jdbcType=VARCHAR}

SELECT T1.ID, T1.TICKET_TYPE, T1.WORK_PLAN_ID, T1.WORK_TICKET_STATUS, T1.WORK_TICKET_STATUS_NAME, TO_CHAR (T1.WORK_DATE, 'yyyy-mm-dd') || ' ' || T1.CLASS_NAME CLASS_NAME, CASE WHEN T3.SHIPVOYAGE_ID IS NOT NULL THEN TO_CHAR (TDS.SHIP_NAME) || '_' || TO_CHAR (TDSI.VOYAGE) END SHIP_NAME_VOYAGE, T4.CARGO_OWNER_NAME || '/' || T4.CARGO_NAME || '/' || T4.CARGO_INFO_NO CARGO_NAME_LABEL, T2.PERSONNEL_ID, T2.PERSONNEL_NAME, T1.DEPT_ID, T1.DEPT_NAME, T2.DEPT_ID DEPT_ITEM_ID, T2.DEPT_NAME DEPT_ITEM_NAME, T2.CABIN_NO, T5.EQUIPMENT_TYPE_NAME, LISTAGG (TO_CHAR(T5.EQUIPMENT_NO), ',') WITHIN GROUP (ORDER BY T5.EQUIPMENT_NO) EQUIPMENT_NO, CASE WHEN T2.STOREHOUSE_NAME_SOURCE IS NOT NULL THEN STOREHOUSE_NAME_SOURCE || '/' || REGION_NAME_SOURCE || '/' || MASS_NAME_SOURCE ELSE NULL END STOREHOUSE_NAME_SOURCE_LABEL, CASE WHEN T2.STOREHOUSE_NAME_TARGET IS NOT NULL THEN STOREHOUSE_NAME_TARGET || '/' || REGION_NAME_TARGET || '/' || MASS_NAME_TARGET ELSE NULL END STOREHOUSE_NAME_TARGET_LABEL, T2.TON, T2.QUANTITY, TO_CHAR(T2.END_TIME,'yyyy-mm-dd hh24:mi') END_TIME, TO_CHAR ( T2.START_TIME, 'yyyy-mm-dd hh24:mi' ) START_TIME, TDSI.LOAD_UNLOAD, T2.PROCESS_DETAIL_NAME, T2.PROCESS_DETAIL_CODE, T1.EXAMINE_BY_NAME, T1.EXAMINE_TIME, T1.CREATE_TIME, T1.CREATE_BY_NAME, T6.TRUST_NO FROM T_PRD_WORK_TICKET T1 LEFT JOIN T_PRD_WORK_TICKET_DETAIL T2 ON T1. ID = T2.WORK_TICKET_ID LEFT JOIN T_PRD_WORK_PLAN T3 ON T3. ID = T1.WORK_PLAN_ID LEFT JOIN T_DIS_SHIPVOYAGE TDS ON T3.SHIPVOYAGE_ID = TDS. ID LEFT JOIN T_DIS_SHIPVOYAGE_ITEM TDSI ON T3.SHIPVOYAGE_ITEM_ID = TDSI. ID LEFT JOIN T_BUS_CARGO_INFO T4 ON T4. ID = T2.CARGO_INFO_ID LEFT JOIN T_PRD_WORK_TICKET_EQUIPMENT T5 ON T5.WORK_TICKET_DETAIL_ID = T2. ID LEFT JOIN T_BUS_TRUST T6 ON T3.TRUST_ID = T6.ID LEFT JOIN M_CARGO T7 ON T7.CARGO_CODE = T4.CARGO_CODE WHERE WORK_TICKET_STATUS IN ('10','20')
AND T3.WORK_DATE = #{workDate}
AND T3.CLASS_CODE = #{classCode}
AND T3.PLAN_TYPE = #{planType}
AND T7.WORK_TYPE = #{cargoType}
AND T3.SHIPVOYAGE_ITEM_ID = #{shipvoyageItemId}
AND T6.PORT_CODE = #{portCode}
GROUP BY T1.ID, T1.TICKET_TYPE, T1.WORK_PLAN_ID, T1.WORK_TICKET_STATUS, T1.WORK_TICKET_STATUS_NAME, TO_CHAR (T1.WORK_DATE, 'yyyy-mm-dd') || ' ' || T1.CLASS_NAME, CASE WHEN T3.SHIPVOYAGE_ID IS NOT NULL THEN TO_CHAR (TDS.SHIP_NAME) || '_' || TO_CHAR (TDSI.VOYAGE) END, T4.CARGO_OWNER_NAME || '/' || T4.CARGO_NAME || '/' || T4.CARGO_INFO_NO, T2.PERSONNEL_ID, T2.PERSONNEL_NAME, T1.DEPT_ID, T1.DEPT_NAME, T2.DEPT_ID, T2.DEPT_NAME, T2.CABIN_NO, T5.EQUIPMENT_TYPE_NAME, CASE WHEN T2.STOREHOUSE_NAME_SOURCE IS NOT NULL THEN STOREHOUSE_NAME_SOURCE || '/' || REGION_NAME_SOURCE || '/' || MASS_NAME_SOURCE ELSE NULL END, CASE WHEN T2.STOREHOUSE_NAME_TARGET IS NOT NULL THEN STOREHOUSE_NAME_TARGET || '/' || REGION_NAME_TARGET || '/' || MASS_NAME_TARGET ELSE NULL END, T2.TON, T2.QUANTITY, T2.CAR_COUNT, T2.END_TIME, T2.START_TIME, TDSI.LOAD_UNLOAD, T2.PROCESS_DETAIL_NAME, T2.PROCESS_DETAIL_CODE, T1.EXAMINE_BY_NAME, T1.EXAMINE_TIME, T1.CREATE_TIME, T1.CREATE_BY_NAME, T6.TRUST_NO ORDER BY T6.TRUST_NO

SELECT A1.TON, A1.QUANTITY, A2.PLAN_ID, A1.CARGO_CODE FROM T_YARD_TALLY_ITEM A1 LEFT JOIN T_YARD_TALLY A2 ON A2. ID = A1.TALLY_ID WHERE A2.PLAN_ID IN
#{item}
AND A2.DEL_FLAG = 0

SELECT SUM(WEIGHT_GOODS) "ton" FROM WFG_PORTMIS_POUND.WEIGHT_RECORD_POUND A1 LEFT JOIN T_BUS_TRUST_CARGO A2 ON A1.PLAN_NO = A2.BUSINESS_NO LEFT JOIN T_BUS_TRUST A3 ON A3. ID = A2.TRUST_ID LEFT JOIN T_YARD_TALLY A4 ON A4.WEIGHBRIDGE_ID = A1.NOTE_ID LEFT JOIN T_YARD_TALLY_ITEM A5 ON A5.TALLY_ID = A4.ID LEFT JOIN M_STORAGE_YARD A6 ON A6.ID = A5.LOCATION_ID WHERE A1.PLAN_NO IN ( SELECT BUSINESS_NO FROM T_BUS_TRUST_CARGO WHERE ID IN
#{item}
) AND GOODS_CODE = #{cargoCode,jdbcType=VARCHAR} AND TO_CHAR (WEIGH_OUT_DT, 'YYYY-MM-DD HH24:MI') >= #{startTime,jdbcType=VARCHAR} AND TO_CHAR (WEIGH_OUT_DT, 'YYYY-MM-DD HH24:MI') <= #{endTime,jdbcType=VARCHAR} AND A3. TYPE IN ('集港', '疏港', '陆销') AND WEIGHT_GOODS != 0 AND WEIGHT_GOODS IS NOT NULL AND A4.DEL_FLAG = 0 AND (A6.IS_FRONTIER = '1')

SELECT STOREHOUSE_ID "storehouseId", STOREHOUSE_NAME "storehouseName", REGION_ID "regionId", REGION_NAME "regionName", MASS_ID "massId", MASS_NAME "massName", WORK_PLAN_ID "workPlanId" FROM T_PRD_WORK_PLAN_LOCATION WHERE WORK_PLAN_ID IN
#{item}
AND DIRECTION = #{type,jdbcType=VARCHAR}

SELECT T1.ID, T3.TRUST_ID, T1.TICKET_TYPE, T1.WORK_PLAN_ID, T1.WORK_TICKET_STATUS, T1.WORK_TICKET_STATUS_NAME, TO_CHAR (T1.WORK_DATE, 'yyyy-mm-dd') || ' ' || T1.CLASS_NAME CLASS_NAME, CASE WHEN T3.SHIPVOYAGE_ID IS NOT NULL THEN TO_CHAR (TDS.SHIP_NAME) || '_' || TO_CHAR (TDSI.VOYAGE) END SHIP_NAME_VOYAGE, T4.CARGO_OWNER_NAME || '/' || T4.CARGO_NAME || '/' || T4.CARGO_INFO_NO CARGO_NAME_LABEL, T2.PERSONNEL_ID, T2.PERSONNEL_NAME, T1.DEPT_ID, T1.DEPT_NAME, T2.DEPT_ID DEPT_ITEM_ID, T2.DEPT_NAME DEPT_ITEM_NAME, T5.EQUIPMENT_TYPE_NAME, LISTAGG (TO_CHAR(T5.EQUIPMENT_NO), ',') WITHIN GROUP (ORDER BY T5.EQUIPMENT_NO) EQUIPMENT_NO, CASE WHEN T2.STOREHOUSE_NAME_SOURCE IS NOT NULL THEN STOREHOUSE_NAME_SOURCE || '/' || REGION_NAME_SOURCE || '/' || MASS_NAME_SOURCE ELSE NULL END STOREHOUSE_NAME_SOURCE_LABEL, CASE WHEN T2.STOREHOUSE_NAME_TARGET IS NOT NULL THEN STOREHOUSE_NAME_TARGET || '/' || REGION_NAME_TARGET || '/' || MASS_NAME_TARGET ELSE NULL END STOREHOUSE_NAME_TARGET_LABEL, T2.TON, T2.QUANTITY, TO_CHAR(T2.END_TIME,'yyyy-mm-dd hh24:mi') END_TIME, TO_CHAR ( T2.START_TIME, 'yyyy-mm-dd hh24:mi' ) START_TIME, TDSI.LOAD_UNLOAD, T2.PROCESS_DETAIL_NAME, T2.PROCESS_DETAIL_CODE, T1.EXAMINE_BY_NAME, T1.EXAMINE_TIME, T1.CREATE_TIME, T1.CREATE_BY_NAME, T6.TRUST_NO FROM T_PRD_WORK_TICKET T1 LEFT JOIN T_PRD_WORK_TICKET_DETAIL T2 ON T1. ID = T2.WORK_TICKET_ID LEFT JOIN T_PRD_WORK_PLAN T3 ON T3. ID = T1.WORK_PLAN_ID LEFT JOIN T_DIS_SHIPVOYAGE TDS ON T3.SHIPVOYAGE_ID = TDS. ID LEFT JOIN T_DIS_SHIPVOYAGE_ITEM TDSI ON T3.SHIPVOYAGE_ITEM_ID = TDSI. ID LEFT JOIN T_BUS_CARGO_INFO T4 ON T4. ID = T2.CARGO_INFO_ID LEFT JOIN T_PRD_WORK_TICKET_EQUIPMENT T5 ON T5.WORK_TICKET_DETAIL_ID = T2. ID LEFT JOIN T_BUS_TRUST T6 ON T3.TRUST_ID = T6.ID LEFT JOIN M_CARGO T7 ON T7.CARGO_CODE = T4.CARGO_CODE WHERE WORK_TICKET_STATUS IN ('10','20')
AND T7.WORK_TYPE = #{cargoType}
AND T6.PORT_CODE = #{portCode}
AND T3.WORK_DATE = #{workDate}
AND T3.CLASS_CODE = #{classCode}
AND T1.WORK_PLAN_ID IN
#{item}
GROUP BY T1.ID, T3.TRUST_ID, T1.TICKET_TYPE, T1.WORK_PLAN_ID, T1.WORK_TICKET_STATUS, T1.WORK_TICKET_STATUS_NAME, TO_CHAR (T1.WORK_DATE, 'yyyy-mm-dd') || ' ' || T1.CLASS_NAME, CASE WHEN T3.SHIPVOYAGE_ID IS NOT NULL THEN TO_CHAR (TDS.SHIP_NAME) || '_' || TO_CHAR (TDSI.VOYAGE) END, T4.CARGO_OWNER_NAME || '/' || T4.CARGO_NAME || '/' || T4.CARGO_INFO_NO, T2.PERSONNEL_ID, T2.PERSONNEL_NAME, T1.DEPT_ID, T1.DEPT_NAME, T2.DEPT_ID, T2.DEPT_NAME, T5.EQUIPMENT_TYPE_NAME, CASE WHEN T2.STOREHOUSE_NAME_SOURCE IS NOT NULL THEN STOREHOUSE_NAME_SOURCE || '/' || REGION_NAME_SOURCE || '/' || MASS_NAME_SOURCE ELSE NULL END, CASE WHEN T2.STOREHOUSE_NAME_TARGET IS NOT NULL THEN STOREHOUSE_NAME_TARGET || '/' || REGION_NAME_TARGET || '/' || MASS_NAME_TARGET ELSE NULL END, T2.TON, T2.QUANTITY, T2.CAR_COUNT, T2.END_TIME, T2.START_TIME, TDSI.LOAD_UNLOAD, T2.PROCESS_DETAIL_NAME, T2.PROCESS_DETAIL_CODE, T1.EXAMINE_BY_NAME, T1.EXAMINE_TIME, T1.CREATE_TIME, T1.CREATE_BY_NAME, T6.TRUST_NO

SELECT TRUST_ID FROM T_PRD_WORK_PLAN WHERE EXISTS ( select * from (
select #{trustId, jdbcType=BIGINT} as TMPID from dual
) a where a.TMPID = ID )

SELECT T1.ID, T3.TRUST_ID, T1.TICKET_TYPE, T1.WORK_PLAN_ID, T1.WORK_TICKET_STATUS, T1.WORK_TICKET_STATUS_NAME, TO_CHAR (T1.WORK_DATE, 'yyyy-mm-dd') || ' ' || T1.CLASS_NAME CLASS_NAME, CASE WHEN T3.SHIPVOYAGE_ID IS NOT NULL THEN TO_CHAR (TDS.SHIP_NAME) || '_' || TO_CHAR (TDSI.VOYAGE) END SHIP_NAME_VOYAGE, T4.CARGO_OWNER_NAME || '/' || T4.CARGO_NAME || '/' || T4.CARGO_INFO_NO CARGO_NAME_LABEL, T2.PERSONNEL_ID, T2.PERSONNEL_NAME, T1.DEPT_ID, T1.DEPT_NAME, T2.DEPT_ID DEPT_ITEM_ID, T2.DEPT_NAME DEPT_ITEM_NAME, T5.EQUIPMENT_TYPE_NAME, LISTAGG (T5.EQUIPMENT_NO, ',') WITHIN GROUP (ORDER BY T5.EQUIPMENT_NO) EQUIPMENT_NO, CASE WHEN T2.STOREHOUSE_NAME_SOURCE IS NOT NULL THEN STOREHOUSE_NAME_SOURCE || '/' || REGION_NAME_SOURCE || '/' || MASS_NAME_SOURCE ELSE NULL END STOREHOUSE_NAME_SOURCE_LABEL, CASE WHEN T2.STOREHOUSE_NAME_TARGET IS NOT NULL THEN STOREHOUSE_NAME_TARGET || '/' || REGION_NAME_TARGET || '/' || MASS_NAME_TARGET ELSE NULL END STOREHOUSE_NAME_TARGET_LABEL, T2.TON, T2.QUANTITY, TO_CHAR(T2.END_TIME,'yyyy-mm-dd hh24:mi') END_TIME, TO_CHAR ( T2.START_TIME, 'yyyy-mm-dd hh24:mi' ) START_TIME, TDSI.LOAD_UNLOAD, T2.PROCESS_DETAIL_NAME, T2.PROCESS_DETAIL_CODE, T1.EXAMINE_BY_NAME, T1.EXAMINE_TIME, T1.CREATE_TIME, T1.CREATE_BY_NAME, T6.TRUST_NO FROM T_PRD_WORK_TICKET T1 LEFT JOIN T_PRD_WORK_TICKET_DETAIL T2 ON T1. ID = T2.WORK_TICKET_ID LEFT JOIN T_PRD_WORK_PLAN T3 ON T3. ID = T1.WORK_PLAN_ID LEFT JOIN T_DIS_SHIPVOYAGE TDS ON T3.SHIPVOYAGE_ID = TDS. ID LEFT JOIN T_DIS_SHIPVOYAGE_ITEM TDSI ON T3.SHIPVOYAGE_ITEM_ID = TDSI. ID LEFT JOIN T_BUS_CARGO_INFO T4 ON T4. ID = T2.CARGO_INFO_ID LEFT JOIN T_PRD_WORK_TICKET_EQUIPMENT T5 ON T5.WORK_TICKET_DETAIL_ID = T2. ID LEFT JOIN T_BUS_TRUST T6 ON T3.TRUST_ID = T6.ID LEFT JOIN M_CARGO T7 ON T7.CARGO_CODE = T4.CARGO_CODE WHERE (WORK_TICKET_STATUS IN ('20') OR IS_OLD = 0)
AND T3.WORK_DATE >= TO_DATE (#{startDay,jdbcType=VARCHAR}, 'YYYY-MM-DD')
AND T3.WORK_DATE <= TO_DATE (#{endDay,jdbcType=VARCHAR}, 'YYYY-MM-DD')
AND T3.CLASS_CODE = #{classCode}
AND T3.PLAN_TYPE = #{planType}
AND T7.WORK_TYPE = #{cargoType}
AND T3.SHIPVOYAGE_ITEM_ID = #{shipvoyageItemId}
AND T6.PORT_CODE = #{portCode}
AND T1.TICKET_TYPE = #{ticketType}
GROUP BY T1.ID, T3.TRUST_ID, T1.TICKET_TYPE, T1.WORK_PLAN_ID, T1.WORK_TICKET_STATUS, T1.WORK_TICKET_STATUS_NAME, TO_CHAR (T1.WORK_DATE, 'yyyy-mm-dd') || ' ' || T1.CLASS_NAME, CASE WHEN T3.SHIPVOYAGE_ID IS NOT NULL THEN TO_CHAR (TDS.SHIP_NAME) || '_' || TO_CHAR (TDSI.VOYAGE) END, T4.CARGO_OWNER_NAME || '/' || T4.CARGO_NAME || '/' || T4.CARGO_INFO_NO, T2.PERSONNEL_ID, T2.PERSONNEL_NAME, T1.DEPT_ID, T1.DEPT_NAME, T2.DEPT_ID, T2.DEPT_NAME, T5.EQUIPMENT_TYPE_NAME, CASE WHEN T2.STOREHOUSE_NAME_SOURCE IS NOT NULL THEN STOREHOUSE_NAME_SOURCE || '/' || REGION_NAME_SOURCE || '/' || MASS_NAME_SOURCE ELSE NULL END, CASE WHEN T2.STOREHOUSE_NAME_TARGET IS NOT NULL THEN STOREHOUSE_NAME_TARGET || '/' || REGION_NAME_TARGET || '/' || MASS_NAME_TARGET ELSE NULL END, T2.TON, T2.QUANTITY, T2.CAR_COUNT, T2.END_TIME, T2.START_TIME, TDSI.LOAD_UNLOAD, T2.PROCESS_DETAIL_NAME, T2.PROCESS_DETAIL_CODE, T1.EXAMINE_BY_NAME, T1.EXAMINE_TIME, T1.CREATE_TIME, T1.CREATE_BY_NAME, T6.TRUST_NO ORDER BY T6.TRUST_NO

SELECT T1.ID, T3.TRUST_ID, T1.TICKET_TYPE, T1.WORK_PLAN_ID, T1.WORK_TICKET_STATUS, T1.WORK_TICKET_STATUS_NAME, TO_CHAR (T1.WORK_DATE, 'yyyy-mm-dd') || ' ' || T1.CLASS_NAME CLASS_NAME, CASE WHEN T3.SHIPVOYAGE_ID IS NOT NULL THEN TO_CHAR (TDS.SHIP_NAME) || '_' || TO_CHAR (TDSI.VOYAGE) END SHIP_NAME_VOYAGE, T4.CARGO_OWNER_NAME, T4.CARGO_NAME, T4.CARGO_INFO_NO, T2.PERSONNEL_ID, T2.PERSONNEL_NAME, T1.DEPT_ID, T1.DEPT_NAME, T2.DEPT_ID DEPT_ITEM_ID, T2.DEPT_NAME DEPT_ITEM_NAME, T5.EQUIPMENT_TYPE_NAME, LISTAGG (T5.EQUIPMENT_NO, ',') WITHIN GROUP (ORDER BY T5.EQUIPMENT_NO) EQUIPMENT_NO, CASE WHEN T2.STOREHOUSE_NAME_SOURCE IS NOT NULL THEN STOREHOUSE_NAME_SOURCE || '/' || REGION_NAME_SOURCE || '/' || MASS_NAME_SOURCE ELSE NULL END STOREHOUSE_NAME_SOURCE_LABEL, CASE WHEN T2.STOREHOUSE_NAME_TARGET IS NOT NULL THEN STOREHOUSE_NAME_TARGET || '/' || REGION_NAME_TARGET || '/' || MASS_NAME_TARGET ELSE NULL END STOREHOUSE_NAME_TARGET_LABEL, T2.TON, T2.QUANTITY, TO_CHAR(T2.END_TIME,'yyyy-mm-dd hh24:mi') END_TIME, TO_CHAR ( T2.START_TIME, 'yyyy-mm-dd hh24:mi' ) START_TIME, TDSI.LOAD_UNLOAD, T2.PROCESS_DETAIL_NAME, T2.PROCESS_DETAIL_CODE, T1.EXAMINE_BY_NAME, T1.EXAMINE_TIME, T1.CREATE_TIME, T1.CREATE_BY_NAME, T6.TRUST_NO FROM (select * from T_PRD_WORK_TICKET where WORK_TICKET_STATUS = 20 or IS_OLD = '0') T1 LEFT JOIN T_PRD_WORK_TICKET_DETAIL T2 ON T1. ID = T2.WORK_TICKET_ID LEFT JOIN T_PRD_WORK_PLAN T3 ON T3. ID = T1.WORK_PLAN_ID LEFT JOIN T_DIS_SHIPVOYAGE TDS ON T3.SHIPVOYAGE_ID = TDS. ID LEFT JOIN T_DIS_SHIPVOYAGE_ITEM TDSI ON T3.SHIPVOYAGE_ITEM_ID = TDSI. ID LEFT JOIN T_BUS_CARGO_INFO T4 ON T4. ID = T2.CARGO_INFO_ID LEFT JOIN T_PRD_WORK_TICKET_EQUIPMENT T5 ON T5.WORK_TICKET_DETAIL_ID = T2. ID LEFT JOIN T_BUS_TRUST T6 ON T3.TRUST_ID = T6.ID LEFT JOIN M_CARGO T7 ON T7.CARGO_CODE = T4.CARGO_CODE
AND T3.WORK_DATE >= TO_DATE (#{startDay,jdbcType=VARCHAR}, 'YYYY-MM-DD')
AND T3.WORK_DATE <= TO_DATE (#{endDay,jdbcType=VARCHAR}, 'YYYY-MM-DD')
AND T3.CLASS_CODE = #{classCode}
AND T3.PLAN_TYPE = #{planType}
AND T7.WORK_TYPE = #{cargoType}
AND T3.SHIPVOYAGE_ITEM_ID = #{shipvoyageItemId}
AND T6.PORT_CODE = #{portCode}
AND T1.TICKET_TYPE = #{ticketType}
GROUP BY T1.ID, T3.TRUST_ID, T1.TICKET_TYPE, T1.WORK_PLAN_ID, T1.WORK_TICKET_STATUS, T1.WORK_TICKET_STATUS_NAME, TO_CHAR (T1.WORK_DATE, 'yyyy-mm-dd') || ' ' || T1.CLASS_NAME, CASE WHEN T3.SHIPVOYAGE_ID IS NOT NULL THEN TO_CHAR (TDS.SHIP_NAME) || '_' || TO_CHAR (TDSI.VOYAGE) END, T4.CARGO_OWNER_NAME, T4.CARGO_NAME, T4.CARGO_INFO_NO, T2.PERSONNEL_ID, T2.PERSONNEL_NAME, T1.DEPT_ID, T1.DEPT_NAME, T2.DEPT_ID, T2.DEPT_NAME, T5.EQUIPMENT_TYPE_NAME, CASE WHEN T2.STOREHOUSE_NAME_SOURCE IS NOT NULL THEN STOREHOUSE_NAME_SOURCE || '/' || REGION_NAME_SOURCE || '/' || MASS_NAME_SOURCE ELSE NULL END, CASE WHEN T2.STOREHOUSE_NAME_TARGET IS NOT NULL THEN STOREHOUSE_NAME_TARGET || '/' || REGION_NAME_TARGET || '/' || MASS_NAME_TARGET ELSE NULL END, T2.TON, T2.QUANTITY, T2.CAR_COUNT, T2.END_TIME, T2.START_TIME, TDSI.LOAD_UNLOAD, T2.PROCESS_DETAIL_NAME, T2.PROCESS_DETAIL_CODE, T1.EXAMINE_BY_NAME, T1.EXAMINE_TIME, T1.CREATE_TIME, T1.CREATE_BY_NAME, T6.TRUST_NO ORDER BY T6.TRUST_NO

SELECT TPWP.ID, TPWP.PLAN_TYPE, TPWP.TRUST_ID, TPWP.HATCH, TPWP.MASS_NAMES_TARGET, TPWP.MASS_NAMES_SOURCE, TPWP.EQUIPMENT_NAMES_FRONT, TPWP.EQUIPMENT_NAMES_BACK, TPWP.EQUIPMENT_NAMES_ASSIST, TPWP.EQUIPMENT_NAMES_RESHIPMENT, TPWP.COMPANY_NAME, TPWP.EXAMINE_BY, TPWP.WORK_DATE, TPWP.CLASS_CODE, TPWP.CLASS_NAME, TDSI.LOAD_UNLOAD, CASE WHEN TPWP.SHIPVOYAGE_ID IS NOT NULL THEN TO_CHAR (TDS.SHIP_NAME) || '_' || TO_CHAR (TDSI.VOYAGE) END shipvoyageLabel, TPWP.PLAN_NO, TPWP.PROCESS_CODE, TPWP.PROCESS_NAME, TPWP.DEPT_NAME, TPWP.QUANTITY_PLAN, TPWP.TON_PLAN, TPWP.START_TIME_PLAN, TPWP.END_TIME_PLAN, TPWP.START_WORK_TIME, TPWP.END_WORK_TIME, TPWP.REMARK, TPWP.STATUS, MC.NM STATUS_LABEL, TPWP.BERTH_NAME, TPWP.FRONT_TALLY_BY_NAME, TPWP.BACK_TALLY_BY_NAME, TPWP.DISPATCH_BY_NAME, TPWP.EQUIPMENT_NAMES_FRONT, TPWP.EQUIPMENT_NAMES_BACK, TPWP.EQUIPMENT_NAMES_ASSIST, TPWP.EQUIPMENT_NAMES_RESHIPMENT, T6.CARGO_OWNER_NAME, T6.CARGO_OWNER_ID, T7.CARGO_AGENT_NAME, T8.CARGO_NAME, T8.CARGO_CODE, T5.TRUST_NO, T2.NUM AS LABOR_NUM, CASE WHEN TPWT.ID IS NULL THEN '待审核' ELSE TO_CHAR( TPWT.WORK_TICKET_STATUS_NAME ) END WORK_TICKET_STATUS_NAME, CASE WHEN LISTAGG ( TO_CHAR( TPWT. TICKET_TYPE ), ',' ) WITHIN GROUP ( ORDER BY TPWT. TICKET_TYPE ) IS NULL THEN '待签票' WHEN LISTAGG ( TO_CHAR( TPWT. TICKET_TYPE ), ',' ) WITHIN GROUP ( ORDER BY TPWT. TICKET_TYPE ) = '1' THEN '调度已签票' WHEN LISTAGG ( TO_CHAR( TPWT. TICKET_TYPE ), ',' ) WITHIN GROUP ( ORDER BY TPWT. TICKET_TYPE ) = '2' THEN '库场已签票' ELSE '调度/库场已签票' END IS_SIGNED
FROM T_PRD_WORK_PLAN TPWP LEFT JOIN T_DIS_SHIPVOYAGE TDS ON TPWP.SHIPVOYAGE_ID = TDS. ID LEFT JOIN M_SHIP MS ON TDS.SHIP_ID = MS. ID LEFT JOIN T_DIS_SHIPVOYAGE_ITEM TDSI ON TPWP.SHIPVOYAGE_ITEM_ID = TDSI. ID JOIN M_CONSTANTS MC ON TPWP.STATUS = MC.CD AND MC.TYPE_CD = 'WORK_PLAN_STATUS' LEFT JOIN T_PRD_WORK_TICKET TPWT ON TPWP. ID = TPWT.WORK_PLAN_ID LEFT JOIN T_BUS_TRUST T5 ON TPWP.TRUST_ID = T5. ID LEFT JOIN ( SELECT REGEXP_REPLACE ( LISTAGG ( TO_CHAR (CARGO_OWNER_NAME), ',' ) WITHIN GROUP (ORDER BY CARGO_OWNER_NAME), '([^,]+)(,\1)+', '\1' ) CARGO_OWNER_NAME, TRUST_ID, REGEXP_REPLACE ( LISTAGG ( TO_CHAR (CARGO_OWNER_ID), ',' ) WITHIN GROUP (ORDER BY CARGO_OWNER_ID), '([^,]+)(,\1)+', '\1' ) CARGO_OWNER_ID FROM T_BUS_TRUST_CARGO GROUP BY TRUST_ID ) T6 ON T5. ID = T6.TRUST_ID LEFT JOIN ( SELECT REGEXP_REPLACE ( LISTAGG (TO_CHAR(CARGO_NAME), ',') WITHIN GROUP (ORDER BY CARGO_NAME), '([^,]+)(,\1)+', '\1' ) CARGO_NAME, REGEXP_REPLACE ( LISTAGG (TO_CHAR(CARGO_CODE), ',') WITHIN GROUP (ORDER BY CARGO_CODE), '([^,]+)(,\1)+', '\1' ) CARGO_CODE, TRUST_ID FROM T_BUS_TRUST_CARGO GROUP BY TRUST_ID ) T8 ON T5. ID = T8.TRUST_ID LEFT JOIN ( SELECT REGEXP_REPLACE ( LISTAGG ( TO_CHAR (CARGO_AGENT_NAME), ',' ) WITHIN GROUP (ORDER BY CARGO_AGENT_NAME), '([^,]+)(,\1)+', '\1' ) CARGO_AGENT_NAME, TRUST_ID FROM T_BUS_TRUST_CARGO GROUP BY TRUST_ID ) T7 ON T5. ID = T7.TRUST_ID LEFT JOIN T_PRD_DISPATCH T2 ON TPWP. ID = T2.WORK_PLAN_ID AND T2.DISPATCH_TYPE = '2' WHERE TPWP.STATUS != 10
AND T3.WORK_DATE >= TO_DATE (#{startDay,jdbcType=VARCHAR}, 'YYYY-MM-DD')
AND T3.WORK_DATE <= TO_DATE (#{endDay,jdbcType=VARCHAR}, 'YYYY-MM-DD')
AND TPWP.CLASS_CODE = #{classCode}
AND TPWP.PLAN_TYPE = #{planType}
AND T5.TRUST_NO = #{trustNo}
AND T5.PORT_CODE = #{portCode}
GROUP BY TPWP.ID, TPWP.PLAN_TYPE, TPWP.TRUST_ID, TPWP.HATCH, TPWP.MASS_NAMES_TARGET, TPWP.MASS_NAMES_SOURCE, TPWP.EQUIPMENT_NAMES_FRONT, TPWP.EQUIPMENT_NAMES_BACK, TPWP.EQUIPMENT_NAMES_ASSIST, TPWP.EQUIPMENT_NAMES_RESHIPMENT, TPWP.COMPANY_NAME, TPWP.EXAMINE_BY, TPWP.WORK_DATE, TPWP.CLASS_CODE, TPWP.CLASS_NAME, TDSI.LOAD_UNLOAD, CASE WHEN TPWP.SHIPVOYAGE_ID IS NOT NULL THEN TO_CHAR (TDS.SHIP_NAME) || '_' || TO_CHAR (TDSI.VOYAGE) END, TPWP.PLAN_NO, TPWP.PROCESS_CODE, TPWP.PROCESS_NAME, TPWP.DEPT_NAME, TPWP.QUANTITY_PLAN, TPWP.TON_PLAN, TPWP.START_TIME_PLAN, TPWP.END_TIME_PLAN, TPWP.START_WORK_TIME, TPWP.END_WORK_TIME, TPWP.REMARK, TPWP.STATUS, MC.NM, TPWP.BERTH_NAME, TPWP.FRONT_TALLY_BY_NAME, TPWP.BACK_TALLY_BY_NAME, TPWP.DISPATCH_BY_NAME, TPWP.EQUIPMENT_NAMES_FRONT, TPWP.EQUIPMENT_NAMES_BACK, TPWP.EQUIPMENT_NAMES_ASSIST, TPWP.EQUIPMENT_NAMES_RESHIPMENT, T6.CARGO_OWNER_NAME, T6.CARGO_OWNER_ID, T7.CARGO_AGENT_NAME, T8.CARGO_NAME, T8.CARGO_CODE, T5.TRUST_NO, T2.NUM, CASE WHEN TPWT.ID IS NULL THEN '待审核' ELSE TO_CHAR( TPWT.WORK_TICKET_STATUS_NAME ) END ORDER BY PLAN_NO

select TO_CHAR(REGEXP_REPLACE(LISTAGG(TO_CHAR(TDS2.SHIP_NAME ||'_'||TDSI2.VOYAGE), ',') WITHIN GROUP ( ORDER BY TDS2.SHIP_NAME ), '([^,]+)(,\1)+', '\1')) "shipNameVoyage", TBCI2.ID "tbci2Id" from T_BUS_CARGO_INFO TBCI2 JOIN T_BUS_TRUST_CARGO TBTC2 ON TBCI2.ID = TBTC2.CARGO_INFO_ID JOIN T_BUS_TRUST TBT2 ON (TBT2.ID = TBTC2.TRUST_ID) JOIN T_DIS_SHIPVOYAGE_ITEM TDSI2 ON TBT2.SHIPVOYAGE_ITEM_ID = TDSI2.ID JOIN T_DIS_SHIPVOYAGE TDS2 ON TDS2.ID = TDSI2.SHIPVOYAGE_ID WHERE EXISTS ( select * from (
select #{trustId, jdbcType=BIGINT} as TMPID from dual
) a where a.TMPID = TBCI2.ID ) GROUP BY TBCI2.ID
